import React, { useState, useEffect } from 'react';
import { View, TextInput, Button, FlatList, Text } from 'react-native';
import { getFirestore, collection, addDoc, query, onSnapshot, orderBy, serverTimestamp } from 'firebase/firestore';
import { initializeApp } from 'firebase/app';

const app = initializeApp(config);
const db = getFirestore(app);



const HomeMain = () => {
  const [posts, setPosts] = useState([]);
  const [input, setInput] = useState('');

  useEffect(() => {
    const q = query(collection(db, "posts"), orderBy("timestamp", "desc"));
    const unsubscribe = onSnapshot(q, snapshot => {
      const postData = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setPosts(postData);
    });

    return unsubscribe;
  }, []);

  const handleAddPost = async () => {
    if (input) {
      try {
        await addDoc(collection(db, "posts"), {
          text: input,
          timestamp: serverTimestamp(),
        });
        setInput('');
      } catch (e) {
        console.error("Error adding post: ", e);
      }
    }
  };

  return (
    <View style={{ flex: 1, padding: 20 }}>
      <View style={{ flexDirection: 'row', marginBottom: 20 }}>
        <TextInput
          value={input}
          onChangeText={setInput}
          placeholder="New Post..."
          style={{ flex: 1, borderColor: 'gray', borderWidth: 1, marginRight: 10 }}
        />
        <Button title="Add" onPress={handleAddPost} />
      </View>
      <FlatList
        data={posts}
        renderItem={({ item }) => (
          <View style={{ padding: 10, borderBottomColor: 'gray', borderBottomWidth: 1 }}>
            <Text>{item.text}</Text>
          </View>
        )}
        keyExtractor={item => item.id}
      />
    </View>
  );
};

export default HomeMain;
